def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        for j in range(1, 6):
            term = ((-1) ** j) * (ratio ** j) / j
            if j % 2 == 0:
                term *= 1.1
            else:
                term *= 0.9
            score += term
        if capacity < item * 1.2:
            score *= 3
            for k in range(1, 4):
                score += ((-1) ** k) * (ratio ** (k+5)) / (k+5)
        elif capacity < item * 2:
            for m in range(3):
                if m % 2 == 0:
                    score += ratio ** (m+2) / (m+2)
                else:
                    score -= ratio ** (m+2) / (m+2)
        else:
            if capacity > item * 4:
                score /= 3
            else:
                score /= 1.5
            for n in range(2, 5):
                if n == 3:
                    score += (ratio ** n) * np.log(capacity + 1)
                else:
                    score -= (ratio ** n) / (n * np.sqrt(capacity + 1))
        if score < 0:
            score = abs(score) * 0.5
        priorities[i] = -score
    return priorities
